{#if tags.length > 0}
        <div class="tag-list">
          {#each tags as tag}
            <span data-testid="tag-chip" class="tag-chip">
              <span class="tag-text">{tag}</span>
              <button class="tag-remove" ...>×</button>
            </span>
          {/each}
          <button class="tag-add" ...>+</button>
        </div>
      {/if}
